VALUES
  ('optometrist-moex-02084', 'optometrist', 'optometrist-moex-108-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '低視力學童以單字型近距離視力表量測視力可以看到20號字，但在閱讀型視力表則對24號字的閱讀較 為流暢，若學童的課本為22號字，要達成最佳閱讀效果，可優先使用下列何種方法？', '["將課本字型直接放大成24號字型大小", "指導學童反覆練習，即可流暢的閱讀20號字的課本", "先調高其閱讀環境的亮度及課本文字對比，再視情況調整字型大小", "先使用低倍率的紙鎮放大鏡或尺狀放大鏡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "6c415b878fb2", "answer_pdf_sha1": "27ac98f16652", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02085', 'optometrist', 'optometrist-moex-108-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關低視力復健的敘述，下列何者正確？', '["要彌補視覺不足，需要其他感官來協助彌補，老年低視力患者因身體機能老化，視覺復健較年輕人更 為困難", "老年低視力患者所需的照明比年輕低視力患者為弱", "低視力患者欲出門散步，可於行走時配戴頭戴式望遠鏡幫助看清遠處", "低視力患者欲使用擴視機，應教導儘量使用能看清的最大倍率"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "6c415b878fb2", "answer_pdf_sha1": "27ac98f16652", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02086', 'optometrist', 'optometrist-moex-108-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關學齡兒童的低視力患者，下列敘述何者正確？', '["在近距離閱讀時，低視力兒童可利用凹面透鏡來使閱讀更順利", "為了看清楚前方的黑板，可以考慮開立手持式單眼的望遠鏡（hand-held monocular telescope）", "學習電腦會削弱低視力兒童使用其他光學輔具的興趣，因此毋需太早接觸電腦", "由於低視力兒童的致病成因都十分穩定，因此對於輔具的需求不會隨著時間有太大的變化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "6c415b878fb2", "answer_pdf_sha1": "27ac98f16652", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02087', 'optometrist', 'optometrist-moex-108-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '某兒童的視覺路徑前段（眼至外側膝狀體lateral geniculate nucleus）未見損傷，然有明顯的視覺引導功能 受損，你受命觀察該兒童視覺行為並記錄，下列各項觀察何者與兒童或有感知運動視物（perception of moving target）的障礙最可能有關？', '["兒童常被地上的玩具絆倒", "與家中小狗玩你丟我撿時常被跑回眼前的小狗嚇一跳", "無法在班級團體照中找出自己的朋友", "和父母散步同時聊天時，容易撞到明顯的障礙物"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "6c415b878fb2", "answer_pdf_sha1": "27ac98f16652", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02088', 'optometrist', 'optometrist-moex-108-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關不同屈光度的低視力患者在教導使用望遠鏡時的敘述，下列何者正確？', '["若未矯正遠視患者的屈光，使用望遠鏡時，其鏡筒對焦的長度應較原來的設計為長", "若低視力患者不熟悉望遠鏡對焦的操作，指導者應先調整對焦後再交予患者使用", "若未矯正近視患者的屈光，使用望遠鏡時，其鏡筒對焦的長度應較原來的設計為長", "若未矯正近視患者的屈光，調整望遠鏡物鏡的倍率可拉高整體的放大倍率"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "6c415b878fb2", "answer_pdf_sha1": "27ac98f16652", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02089', 'optometrist', 'optometrist-moex-108-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '教導遠視未矯正的低視力患者使用放大鏡時需要注意的事項，下列敘述何者正確？', '["未矯正遠視的低視力患者適合把放大鏡貼近眼睛使用", "放大鏡貼近眼睛使用雖然整體倍率會下降，但可視範圍會大於放大鏡本身的直徑", "放大鏡貼近眼睛使用雖然整體倍率會下降，且可視範圍不變", "對遠視患者而言，不矯正其屈光比矯正屈光，其使用放大鏡的效果愈好"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "6c415b878fb2", "answer_pdf_sha1": "27ac98f16652", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02090', 'optometrist', 'optometrist-moex-108-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '人導法是常使用於引導視障者的方式，下列那一種引導模式不妥當？', '["引導時，引導人應該距離視障者約半步走在前方", "引導視障者入座時，引導人應將視障者的手引導至椅背上，他即可自行檢查入座", "引導人宜扣住視障者的手肘，與其相鄰，以輕推方式引導", "上下樓梯或路面變化時，宜先停頓，輔以口頭提示再行動"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "6c415b878fb2", "answer_pdf_sha1": "27ac98f16652", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02091', 'optometrist', 'optometrist-moex-108-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '對於完全沒有口語反應的低視力幼兒，其評估環境設計何者錯誤？', '["可選擇在開放的空間或較大的室內空間進行", "可利用幼兒有興趣的玩具做為視標", "量測的工具結果無法換算視力值，不能當做教學與訓練的參考", "由家長或熟悉的家人陪同較能減低幼兒的恐懼感"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "6c415b878fb2", "answer_pdf_sha1": "27ac98f16652", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02092', 'optometrist', 'optometrist-moex-108-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '低視力患者閱讀書面資料時，下列敘述何者正確？', '["一定要把低視力患者要閱讀的文件放大，愈大愈好", "提供放大鏡給低視力患者閱讀可能是最省錢及最方便有效的方法", "為了讓低視力患者的眼睛不要再次傷害，可以請他們學習點字", "低視力患者配戴一般的鏡片也沒有太大的成效，所以直接處方放大鏡即可"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "6c415b878fb2", "answer_pdf_sha1": "27ac98f16652", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02093', 'optometrist', 'optometrist-moex-108-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '低視力患者領取身心障礙證明後，可直接申請那些福利與服務而不需要再經過評估？①輔具  ②社會保險', '["長期照護服務", "生活補助  ⑤購屋貸款利息補貼  ⑥必要陪伴者優惠  ⑦日間、住宿 式照顧服務及費用補助", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "6c415b878fb2", "answer_pdf_sha1": "27ac98f16652", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
